const intent = $('Get Intent Status').first().json;

if (!intent || !intent.id) {
  return [{ json: {
    success: false,
    error_code: 'NOT_FOUND',
    error_message: 'Booking intent not found',
    data: null,
    _meta: {
      source: 'WF9_Booking_Intent_Status',
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    }
  }}];
}

// Map status to user-friendly message
const statusMessages = {
  'PENDING': 'Booking request is queued for processing',
  'PROCESSING': 'Booking is being processed',
  'COMPLETED': 'Booking completed successfully',
  'FAILED': 'Booking processing failed',
  'CANCELLED': 'Booking was cancelled'
};

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    intent_id: intent.id,
    status: intent.status,
    status_message: statusMessages[intent.status] || 'Unknown status',
    provider_id: intent.provider_id,
    service_id: intent.service_id,
    start_time: intent.start_time,
    booking_id: intent.booking_id,
    gcal_event_id: intent.gcal_event_id,
    retry_count: intent.retry_count,
    created_at: intent.created_at,
    updated_at: intent.updated_at,
    processed_at: intent.processed_at,
    completed_at: intent.completed_at,
    error_message: intent.error_message
  },
  _meta: {
    source: 'WF9_Booking_Intent_Status',
    timestamp: new Date().toISOString(),
    version: '1.0.0'
  }
}}];
